def process_graph(graph_data):
    graph_copy = graph_data.copy()

    # Find the AGG_BLOCK node with name 'ju1.a3.m1'
    agg_block_node = None
    for node in graph_copy.nodes(data=True):
        if node[1]['name'] == 'ju1.a3.m1' and 'EK_AGG_BLOCK' in node[1]['type']:
            agg_block_node = node[0]
            break

    if not agg_block_node:
        return {
            'type': 'text',
            'data': 'AGG_BLOCK node ju1.a3.m1 not found',
            'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
        }

    # Find all child nodes of type EK_PACKET_SWITCH under this AGG_BLOCK
    child_nodes = []
    for successor in graph_copy.successors(agg_block_node):
        edge_data = graph_copy.get_edge_data(agg_block_node, successor)
        if edge_data and edge_data.get('type') == 'RK_CONTAINS':
            node_data = graph_copy.nodes[successor]
            if 'EK_PACKET_SWITCH' in node_data['type']:
                child_nodes.append(successor)

    # Calculate capacity for each child node (sum of all its PORT capacities)
    child_capacities = []
    for child in child_nodes:
        total_capacity = 0
        # Find all PORT nodes under this PACKET_SWITCH
        for node in nx.descendants(graph_copy, child):
            node_data = graph_copy.nodes[node]
            if 'EK_PORT' in node_data['type']:
                total_capacity += node_data.get('physical_capacity_bps', 0)
        child_capacities.append((graph_copy.nodes[child]['name'], total_capacity))

    # Sort by capacity in descending order
    child_capacities.sort(key=lambda x: x[1], reverse=True)

    return {
        'type': 'list',
        'data': child_capacities,
        'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
    }

