    for node in graph_copy.nodes(data=True):
        if node[1]['name'] == 'ju1.a1.m4.s3c8' and ('EK_PACKET_SWITCH' in node[1]['type'] or 'EK_JUPITER' in node[1]['type']):
            parent_node = node[0]
            break

    if parent_node is None:
        return {
            'type': 'list',
            'data': [],
            'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
        }

    # Get all direct child nodes (contained by parent_node via RK_CONTAINS)
    child_nodes = []
    for succ in graph_copy.successors(parent_node):
        edge_data = graph_copy.get_edge_data(parent_node, succ)
        if edge_data and 'type' in edge_data and edge_data['type'] == 'RK_CONTAINS':
            child_nodes.append(succ)

    # Calculate total capacity for each child node
    child_capacities = []
